{
  "plan_description": "Configure AIDE to use FIPS 140-2 for validating hashes by adding the sha512 option to the NORMAL ruleset in /etc/aide.conf",
  "commands": [
    {
      "command": "read_file /etc/aide.conf",
      "params": {}
    },
    {
      "command": "run_cmd sed -i 's/NORMAL = FIPSR/NORMAL = FIPSR+sha512/' /etc/aide.conf",
      "params": {}
    },
    {
      "command": "write_file /etc/aide.conf",
      "params": {}
    }
  ]
}
